import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

async function generateCompliantAdvice(customerProfile: any) {
  const response = await anthropic.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    tools: [investment_recommendation_tool],
    messages: [{ role: 'user', content: `Recommend portfolio for ${JSON.stringify(customerProfile)}` }]
  });

  const advice = response.content[0].text;

  // Vex verification for SEC compliance
  const result = await vex.verify({
    input: customerProfile,
    output: advice,
    policy: 'sec-best-interest',
    context: {
      requiresDisclaimer: true,
      explainabilityLevel: 'high',
      regulatedAdvice: true,
      customerRiskProfile: customerProfile.risk_tolerance
    }
  });

  if (result.passed) {
    return { advice, compliant: true };
  } else {
    throw new Error(`Non-compliant advice: ${result.issues}`);
  }
}
